class Solution {
    public boolean canIWin(int maxChoosableInteger, int desiredTotal) {
        if (desiredTotal <= 0) {
            return true;
        }
        if (maxChoosableInteger * (maxChoosableInteger + 1) / 2 < desiredTotal) {
            return false;
        }
        Set<Integer> used = new HashSet<>();
        return canIWinHelper(maxChoosableInteger, desiredTotal, used);
    }
    private boolean canIWinHelper(int maxChoosableInteger, int desiredTotal, Set<Integer> used) {
        if (desiredTotal == 0) {
            return true;
        }
        for (int i = 1; i <= maxChoosableInteger; i++) {
            if (!used.contains(i)) {
                used.add(i);
                if (!canIWinHelper(maxChoosableInteger, desiredTotal - i, used)) {
                    return true;
                }
                used.remove(i);
            }
        }
        return false;
    }
}
